// bunku-mascot.js
// Drop-in canvas mascot — works on iOS, Android, all browsers.

(function () {
  "use strict";

  // ── CONFIG ──────────────────────────────────────────────
  const FPS = 15;
  const FRAME_COUNT = 75;
  const IDLE_MIN_MS = 4000;
  const IDLE_MAX_MS = 6000;

  const FRAMES_SRC = [
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
  ];
  // ────────────────────────────────────────────────────────

  const canvas = document.getElementById("bunku-mascot");
  if (!canvas || canvas.tagName !== "CANVAS") {
    console.warn('bunku-mascot: no <canvas id="bunku-mascot"> found.');
    return;
  }

  const ctx = canvas.getContext("2d");
  const interval = 1000 / FPS;

  let images = new Array(FRAME_COUNT);
  let loaded = 0;
  let frame = 0;
  let playing = false;
  let lastTime = null;
  let rafHandle = null;
  let idleTimer = null;

  // ── Preload all frames ──
  function preload() {
    FRAMES_SRC.forEach((src, i) => {
      const img = new Image();
      img.onload = () => {
        images[i] = img;
        if (++loaded === FRAME_COUNT) onReady();
      };
      img.onerror = () => {
        if (++loaded === FRAME_COUNT) onReady();
      };
      img.src = src;
    });
  }

  // ── Called once all frames are loaded ──
  function onReady() {
    drawFrame(0); // show frame 0 (frozen)
    schedulePlay(1500); // greet after 1.5 s
  }

  // ── Draw a single frame to canvas ──
  function drawFrame(n) {
    if (!images[n]) return;
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.drawImage(images[n], 0, 0, canvas.width, canvas.height);
  }

  // ── Schedule the next playthrough ──
  function schedulePlay(delay) {
    clearTimeout(idleTimer);
    idleTimer = setTimeout(playOnce, delay ?? randomIdle());
  }

  function randomIdle() {
    return IDLE_MIN_MS + Math.random() * (IDLE_MAX_MS - IDLE_MIN_MS);
  }

  // ── Play the animation once, then go idle ──
  function playOnce() {
    if (playing) return;
    playing = true;
    frame = 0;
    lastTime = null;
    rafHandle = requestAnimationFrame(tick);
  }

  function tick(ts) {
    if (lastTime === null) lastTime = ts;
    const elapsed = ts - lastTime;

    if (elapsed >= interval) {
      lastTime = ts - (elapsed % interval);
      drawFrame(frame);
      frame++;

      if (frame >= FRAME_COUNT) {
        // animation complete
        playing = false;
        cancelAnimationFrame(rafHandle);
        drawFrame(0); // freeze on frame 0
        schedulePlay(); // schedule next wave
        return;
      }
    }
    rafHandle = requestAnimationFrame(tick);
  }

  // ── Pause when tab is hidden (battery / perf) ──
  document.addEventListener("visibilitychange", () => {
    if (document.hidden) {
      cancelAnimationFrame(rafHandle);
      clearTimeout(idleTimer);
    } else if (!playing) {
      schedulePlay(1000);
    }
  });

  preload();
})();
